import React, { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import Navbar from "./Navbar";
import Footer from "./Footer";

function Doctorprofile() {
  const { doctor_id } = useParams();
  const navigate = useNavigate();

  const [doctor, setDoctor] = useState(null);
  const [availableDays, setAvailableDays] = useState([]);
  const [availableTimes, setAvailableTimes] = useState([]);

  const [date, setDate] = useState("");
  const [time, setTime] = useState("");

  const [feedbacks, setFeedbacks] = useState([]);
  const [rating, setRating] = useState("");
  const [comment, setComment] = useState("");

  const [popup, setPopup] = useState({ show: false, message: "" });

  // ================= GET DOCTOR =================
  useEffect(() => {
    fetch(`http://127.0.0.1:8000/doctor-details/${doctor_id}/`, {
      headers: {
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
    })
      .then((res) => res.json())
      .then((data) => {
        setDoctor(data.doctor);
        setAvailableDays(data.doctor.available_days || []);
        setAvailableTimes(data.doctor.available_time_slots || []);
      });
  }, [doctor_id]);

  // ================= GET FEEDBACK =================
  useEffect(() => {
    fetch(`http://127.0.0.1:8000/doctor-feedback/${doctor_id}/`, {
      headers: {
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
    })
      .then((res) => res.json())
      .then((data) => setFeedbacks(data));
  }, [doctor_id]);

  // ================= AVG RATING =================
  const avgRating =
    feedbacks.length > 0
      ? (
          feedbacks.reduce((sum, fb) => sum + fb.rating, 0) /
          feedbacks.length
        ).toFixed(1)
      : 0;

  // ================= DAY CHECK =================
  const getDayName = (dateStr) =>
    new Date(dateStr).toLocaleDateString("en-US", {
      weekday: "long",
    });

  const handleDateChange = (e) => {
    const selected = e.target.value;
    const dayName = getDayName(selected);

    if (!availableDays.includes(dayName)) {
      setPopup({ show: true, message: `Doctor not available on ${dayName}` });
      setDate("");
      return;
    }

    setDate(selected);
  };

  // ================= BOOK =================
  const handleNext = async () => {
    if (!date || !time) {
      setPopup({ show: true, message: "Please select date and time" });
      return;
    }

    const token = localStorage.getItem("token");
    if (!token) {
      navigate("/login");
      return;
    }

    try {
      const res = await fetch("http://127.0.0.1:8000/book-appointment/", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Token ${token}`,
        },
        body: JSON.stringify({
          doctor_id,
          appointment_date: date,
          time_slot: time,
        }),
      });

      const data = await res.json();

      if (res.ok) {
        setPopup({ show: true, message: "Appointment booked successfully!" });

        setTimeout(() => {
          navigate("/myappointments");
        }, 1200);
      } else {
        setPopup({ show: true, message: data.error || "Booking failed" });
      }
    } catch {
      setPopup({ show: true, message: "Server error" });
    }
  };

  // ================= FEEDBACK =================
  const handleSubmitFeedback = () => {
    if (!rating || !comment) {
      setPopup({ show: true, message: "Please add rating & comment" });
      return;
    }

    fetch(`http://127.0.0.1:8000/doctor-feedback/${doctor_id}/`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
      body: JSON.stringify({ rating, comment }),
    })
      .then((res) => res.json())
      .then((data) => {
        setFeedbacks([data, ...feedbacks]);
        setRating("");
        setComment("");
      });
  };

  if (!doctor) return <h2 style={styles.loading}>Loading...</h2>;

  return (
    <div style={styles.page}>
      <Navbar />

      {/* ================= POPUP ================= */}
      {popup.show && (
        <div style={styles.overlay}>
          <div style={styles.popupCard}>
            <h3 style={{ marginBottom: "10px" }}>Notice</h3>
            <p>{popup.message}</p>
            <button
              style={styles.popupBtn}
              onClick={() => setPopup({ show: false, message: "" })}
            >
              OK
            </button>
          </div>
        </div>
      )}

      <div style={styles.container}>
        <div style={styles.card}>

          {/* LEFT */}
          <div style={styles.left}>
            <img
              src={
                doctor.image ||
                "https://cdn-icons-png.flaticon.com/512/387/387561.png"
              }
              alt={doctor.name}
              style={styles.image}
            />
          </div>

          {/* RIGHT */}
          <div style={styles.right}>
            <h2>{doctor.name}</h2>
            <p><b>Specialization:</b> {doctor.field}</p>
            <p><b>Experience:</b> {doctor.experience}</p>
            <p><b>Qualification:</b> {doctor.qualification}</p>

            {/* BOOKING */}
            <div style={styles.bookingBox}>
              <input type="date" value={date} onChange={handleDateChange} style={styles.input} />

              <select value={time} onChange={(e) => setTime(e.target.value)} style={styles.input}>
                <option value="">Select Time</option>
                {availableTimes.map((t, i) => (
                  <option key={i}>{t}</option>
                ))}
              </select>

              <button style={styles.bookBtn} onClick={handleNext}>
                Book Appointment
              </button>
            </div>

            {/* FEEDBACK */}
            <div style={styles.feedbackBox}>
              <h3>Reviews ({avgRating} ⭐)</h3>

              <select value={rating} onChange={(e) => setRating(e.target.value)} style={styles.input}>
                <option value="">Rating</option>
                <option value="5">⭐⭐⭐⭐⭐</option>
                <option value="4">⭐⭐⭐⭐</option>
                <option value="3">⭐⭐⭐</option>
                <option value="2">⭐⭐</option>
                <option value="1">⭐</option>
              </select>

              <textarea
                value={comment}
                onChange={(e) => setComment(e.target.value)}
                style={styles.textarea}
                placeholder="Write your review..."
              />

              <button onClick={handleSubmitFeedback} style={styles.reviewBtn}>
                Submit Review
              </button>
            </div>

          </div>
        </div>
      </div>

      <Footer />
    </div>
  );
}

export default Doctorprofile;

/* ================= PROFESSIONAL STYLES ================= */
const styles = {
  page: {
    background: "#f4f6f9",
    minHeight: "100vh",
  },

  container: {
    display: "flex",
    justifyContent: "center",
    padding: "30px",
  },

  card: {
    display: "flex",
    gap: "30px",
    background: "#fff",
    padding: "30px",
    borderRadius: "12px",
    width: "900px",
    boxShadow: "0 8px 25px rgba(0,0,0,0.1)",
  },

  left: {
    flex: "0.4",
    display: "flex",
    justifyContent: "center",
  },

  right: {
    flex: "0.6",
  },

  image: {
    width: "160px",
    height: "160px",
    borderRadius: "50%",
    objectFit: "cover",
  },

  bookingBox: {
    marginTop: "20px",
    display: "flex",
    flexDirection: "column",
    gap: "10px",
  },

  input: {
    padding: "10px",
    borderRadius: "6px",
    border: "1px solid #ccc",
  },

  textarea: {
    padding: "10px",
    borderRadius: "6px",
    border: "1px solid #ccc",
    height: "80px",
  },

  bookBtn: {
    background: "#2c3e50",
    color: "#fff",
    padding: "10px",
    borderRadius: "6px",
    border: "none",
    cursor: "pointer",
  },

  feedbackBox: {
    marginTop: "20px",
  },

  reviewBtn: {
    marginTop: "10px",
    background: "#16a085",
    color: "#fff",
    padding: "10px",
    border: "none",
    borderRadius: "6px",
  },

  /* POPUP */
  overlay: {
    position: "fixed",
    top: 0,
    left: 0,
    height: "100%",
